    const fetchChartData = async () => {
      try {
        // Fetch work days for charts
        const now = new Date();
        const currentYear = now.getFullYear();
        const currentMonth = now.getMonth() + 1;

        // Get work days for current month
        const workResponse = await api.get('/work/days', {
          params: {
            month: currentMonth,
            year: currentYear
